1	type Item = { type: string; material?: string; enchantment?: number; cursed?: boolean };
2	type Step = { op: "quote"; items: Item[] };
3	type Scenario = { customer: { yearsWithMHPCO: number }; steps: Step[] };
4	
5	const PROCESSING_FEE = 5;
6	const FIRST_INSURANCE_SURCHARGE = 0.1;
7	const CURSE_SURCHARGE = 0.5;
8	const HIGH_ENCHANTMENT_SURCHARGE = 0.3;
9	const HIGH_ENCHANTMENT_THRESHOLD = 5;
10	const COMPONENT_BLOCK_SIZE = 3;
11	const COMPONENT_BLOCK_PRICE = 60;
12	
13	const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
14	  sword: 100,
15	  amulet: 60,
16	  staff: 80,
17	  potion: 40,
18	  rune: 25,
19	  moonstone: 25,
20	};
21	
22	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
23	
24	const basePremiumOf = (item: Item): number => BASE_PREMIUM_BY_TYPE[item.type];
25	
26	const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);
27	
28	const priceForComponentGroup = (type: string, count: number): number =>
29	  count === COMPONENT_BLOCK_SIZE
30	    ? COMPONENT_BLOCK_PRICE
31	    : count * BASE_PREMIUM_BY_TYPE[type];
32	
33	const countByType = (items: Item[]): Map<string, number> => {
34	  const counts = new Map<string, number>();
35	  for (const item of items) {
36	    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
37	  }
38	  return counts;
39	};
40	
41	const sumBasePremiumsFor = (items: Item[]): number => {
42	  const mainItemsTotal = items
43	    .filter((item) => !isComponent(item))
44	    .reduce((sum, item) => sum + basePremiumOf(item), 0);
45	
46	  const componentsTotal = Array.from(countByType(items.filter(isComponent)))
47	    .reduce((sum, [type, count]) => sum + priceForComponentGroup(type, count), 0);
48	
49	  return mainItemsTotal + componentsTotal;
50	};
51	
52	// Item surcharges: each rule adds a percentage of the item's base premium when it applies.
53	const ITEM_SURCHARGE_RULES: { applies: (item: Item) => boolean; rate: number }[] = [
54	  { applies: (item) => item.cursed === true, rate: CURSE_SURCHARGE },
55	  { applies: (item) => (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD, rate: HIGH_ENCHANTMENT_SURCHARGE },
56	];
57	
58	const surchargeRateFor = (item: Item): number =>
59	  ITEM_SURCHARGE_RULES.reduce((rate, rule) => rate + (rule.applies(item) ? rule.rate : 0), 0);
60	
61	const itemSurchargesFor = (items: Item[]): number =>
62	  items.reduce((sum, item) => sum + basePremiumOf(item) * surchargeRateFor(item), 0);
63	
64	const computePremium = (items: Item[]): number => {
65	  const policyBase = sumBasePremiumsFor(items);
66	  const itemSurcharges = itemSurchargesFor(items);
67	  const firstInsurance = policyBase * FIRST_INSURANCE_SURCHARGE;
68	  return policyBase + itemSurcharges + firstInsurance + PROCESSING_FEE;
69	};
70	
71	// Rounds up to the nearest whole gold piece, in MHPCO's favor.
72	// Cleans float noise (e.g. 66.00000000000001) before ceiling.
73	const roundUpToGold = (amount: number): number =>
74	  Math.ceil(Math.round(amount * 1e6) / 1e6);
75	
76	export const runScenario = (scenario: Scenario): { results: { premium: number }[] } => {
77	  const results = scenario.steps.map((step) => ({
78	    premium: roundUpToGold(computePremium(step.items)),
79	  }));
80	  return { results };
81	};
